
#nullable enable

namespace Braintrust
{
    /// <summary>
    /// A special value that indicates the span was generated by a scoring automation
    /// </summary>
    public enum SpanAttributesPurpose
    {
        /// <summary>
        /// 
        /// </summary>
        Scorer,
    }

    /// <summary>
    /// Enum extensions to do fast conversions without the reflection.
    /// </summary>
    public static class SpanAttributesPurposeExtensions
    {
        /// <summary>
        /// Converts an enum to a string.
        /// </summary>
        public static string ToValueString(this SpanAttributesPurpose value)
        {
            return value switch
            {
                SpanAttributesPurpose.Scorer => "scorer",
                _ => throw new global::System.ArgumentOutOfRangeException(nameof(value), value, null),
            };
        }
        /// <summary>
        /// Converts an string to a enum.
        /// </summary>
        public static SpanAttributesPurpose? ToEnum(string value)
        {
            return value switch
            {
                "scorer" => SpanAttributesPurpose.Scorer,
                _ => null,
            };
        }
    }
}